    let total_w = buffer.width() as usize;
    let block_x = total_w.saturating_sub(block_w) / 2;
    let mut y = total_h.saturating_sub(height) / 2;

    // Title centered within block.
    let title_offset = block_w.saturating_sub(title_w) / 2;
