fn defense_breakdown(state: &RunState, level: u32, equipment: Equipment) -> StatBreakdown {
    let base = config::PLAYER.base_defense;
    let level_bonus = config::PLAYER.level_up_defense * level.saturating_sub(1) as i32;
    let armor_bonus = equipment
        .armor
        .and_then(|entity| item_defense_bonus(state, entity))
        .unwrap_or(0);
    let ring_bonus = equipment
        .ring
        .and_then(|entity| ring_defense_bonus(state, entity))
        .unwrap_or(0);
    let gear_bonus = armor_bonus + ring_bonus;
    StatBreakdown {
        total: base + level_bonus + gear_bonus,
        base,
        level: level_bonus,
        gear: gear_bonus,
        buff: 0,
    }
}

fn format_stat_line(actual: i32, breakdown: StatBreakdown) -> String {
    let mut parts = vec![
        format!("{} base", breakdown.base),
        format!("{} lvl", breakdown.level),
        format!("{} gear", breakdown.gear),
    ];
    if breakdown.buff != 0 {
        parts.push(format!("{} buff", breakdown.buff));
    }
    let known = breakdown.base + breakdown.level + breakdown.gear + breakdown.buff;
    let extra = actual - known;
    if extra != 0 {
        parts.push(format!("{extra} extra"));
    }
    format!("{} ({})", actual, parts.join(" + "))
}

fn item_attack_bonus(state: &RunState, entity: hecs::Entity) -> Option<i32> {
    match state.world.get::<&Item>(entity).ok()?.kind {
        ItemKind::Weapon { attack_bonus } => Some(attack_bonus),
        _ => None,
    }
}

fn item_defense_bonus(state: &RunState, entity: hecs::Entity) -> Option<i32> {
    match state.world.get::<&Item>(entity).ok()?.kind {
        ItemKind::Armor { defense_bonus } => Some(defense_bonus),
        _ => None,
    }
}

fn ring_defense_bonus(state: &RunState, entity: hecs::Entity) -> Option<i32> {
    match state.world.get::<&Item>(entity).ok()?.kind {
        ItemKind::Ring(RingEffect::Protection) => Some(1),
        _ => None,
    }
}

fn active_effects(effects: &StatusEffects) -> String {
    let mut parts = Vec::new();
    if effects.poison_turns > 0 {
        parts.push(format!(
            "poison {}x{}",
            effects.poison_turns, effects.poison_dmg
        ));
    }
    if effects.paralysis_turns > 0 {
        parts.push(format!("paralysis {}", effects.paralysis_turns));
    }
    if effects.fear_turns > 0 {
        parts.push(format!("fear {}", effects.fear_turns));
    }
    if effects.attack_buff_turns > 0 {
        parts.push(format!(
            "attack+{} {}t",
            effects.attack_buff, effects.attack_buff_turns
        ));
    }
    if effects.vision_buff_turns > 0 {
        parts.push(format!(
            "sight+{} {}t",
            effects.vision_buff, effects.vision_buff_turns
        ));
    }
    if effects.regen_per_turn > 0 {
        parts.push(format!("regen {}", effects.regen_per_turn));
    }
    if effects.light_turns > 0 {
        parts.push(format!("light {}", effects.light_turns));
    }
    if effects.invisible {
        parts.push("invisible".to_string());
    }
    if parts.is_empty() {
        "none".to_string()
    } else {
        parts.join(", ")
    }
}

fn stat_line_omits_zero_extra_and_zero_buff() {
        let text = format_stat_line(
            7,
            StatBreakdown { total: 7, base: 0, level: 1, gear: 6, buff: 0 },
        );
        assert_eq!(text, "7 (0 base + 1 lvl + 6 gear)");
    }

fn stat_line_includes_buff_segment_when_active() {
        let text = format_stat_line(
            9,
            StatBreakdown { total: 9, base: 0, level: 1, gear: 6, buff: 2 },
        );
        assert_eq!(text, "9 (0 base + 1 lvl + 6 gear + 2 buff)");
    }

fn stat_line_surfaces_residual_when_breakdown_undercounts() {
        // Legacy buff-stack residual: live stat is 7 but base+lvl+gear+buff
        // only sums to 4. The extra +3 must be visible so the parens add up.
        let text = format_stat_line(
            7,
            StatBreakdown {
                total: 4,
                base: 1,
                level: 1,
                gear: 2,
                buff: 0,
            },
        );
        assert_eq!(text, "7 (1 base + 1 lvl + 2 gear + 3 extra)");
    }

//! Modal screens overlaid on top of the map: inventory, death, etc.

use crossterm::style::Color;
use hecs::{Entity, World};

use crate::character::inventory_capacity;
use crate::ecs::components::{
    AmuletEffect, Equipment, Inventory, Item, ItemKind, Name, Player, PotionEffect,
    Progression, RingEffect, ScrollKind, ThrowableKind, WandKind,
};
use crate::ui::Buffer;

pub fn draw_inventory(world: &World, buffer: &mut Buffer, cursor: usize) {
    if buffer.height() == 0 || buffer.width() == 0 {
        return;
    }
    // Translucent darken: clear to background.
    for y in 0..buffer.height() {
        for x in 0..buffer.width() {
            buffer.put(x, y, crate::ui::Cell::BLANK);
        }
    }

    let player = match world.query::<&Player>().iter().next().map(|(e, _)| e) {
        Some(p) => p,
        None => return,
    };
    let lines = build_lines(world, player, cursor, buffer.height() as usize);
    let start_y = (buffer.height() as usize)
        .saturating_sub(lines.len())
        / 2;
    for (i, (text, color)) in lines.iter().enumerate() {
        let y = (start_y + i) as u16;
        let truncated = take_chars(text, buffer.width() as usize);
        buffer.put_str(2, y, &truncated, *color, Color::Reset);
    }
}

fn build_lines(
    world: &World,
    player: Entity,
    cursor: usize,
    screen_rows: usize,
) -> Vec<(String, Color)> {
    let mut out: Vec<(String, Color)> = Vec::new();
    let inv = match world.get::<&Inventory>(player) {
        Ok(i) => i.clone(),
        Err(_) => return out,
    };
    let level = world
        .get::<&Progression>(player)
        .map(|p| p.level)
        .unwrap_or(1);
    let capacity = inventory_capacity(level);
    out.push((format!("Inventory {}/{}", inv.items.len(), capacity), Color::Yellow));
    out.push((String::new(), Color::Reset));
    let equipment = world
        .get::<&Equipment>(player)
        .map(|e| *e)
        .unwrap_or_default();
    if inv.items.is_empty() {
        out.push(("  (empty)".to_string(), Color::DarkGrey));
    }
    let reserved_rows = 4usize;
    let visible_rows = screen_rows.saturating_sub(reserved_rows).max(1);
    let item_start = cursor.saturating_add(1).saturating_sub(visible_rows);
    let item_end = (item_start + visible_rows).min(inv.items.len());
    for (idx, entity) in inv
        .items
        .iter()
        .enumerate()
        .skip(item_start)
        .take(item_end.saturating_sub(item_start))
    {
        let name = world
            .get::<&Name>(*entity)
            .map(|n| n.0.clone())
            .unwrap_or_else(|_| "?".into());
        let descriptor = describe(world, *entity);
        let equipped = matches!(equipment.weapon, Some(w) if w == *entity)
            || matches!(equipment.armor, Some(a) if a == *entity)
            || matches!(equipment.ring, Some(r) if r == *entity)
            || matches!(equipment.amulet, Some(a) if a == *entity);
        let mark = if equipped { " [E]" } else { "" };
        let prefix = if idx == cursor { ">" } else { " " };
        let color = if idx == cursor { Color::Cyan } else { Color::White };
        out.push((format!("  {prefix} {name}{mark} {descriptor}"), color));
    }
    out.push((String::new(), Color::Reset));
    out.push((
        "  up/down select   f use/equip   g sell   esc/i close".to_string(),
        Color::DarkGrey,
    ));
    out
}

fn describe(world: &World, item: Entity) -> String {
    let kind = match world.get::<&Item>(item) {
        Ok(i) => i.kind,
        Err(_) => return String::new(),
    };
    match kind {
        ItemKind::Potion(p) => describe_potion(p),
        ItemKind::Scroll(s) => describe_scroll(s).to_string(),
        ItemKind::Weapon { attack_bonus } => format!("(+{attack_bonus} atk)"),
        ItemKind::Armor { defense_bonus } => format!("(+{defense_bonus} def)"),
        ItemKind::Ring(r) => format!("({})", describe_ring(r)),
        ItemKind::AmuletItem(a) => format!("({})", describe_amulet(a)),
        ItemKind::Wand { kind, charges } => {
            format!("({} {} charges)", describe_wand(kind), charges)
        }
        ItemKind::Throwable(t) => format!("({})", describe_throwable(t)),
        ItemKind::Food { nutrition, poisonous } => {
            if poisonous {
                format!("(+{nutrition} food, suspicious)")
            } else {
                format!("(+{nutrition} food)")
            }
        }
        ItemKind::Corpse => "(corpse)".to_string(),
    }
}

fn describe_potion(p: PotionEffect) -> String {
    match p {
        PotionEffect::Heal(n) => format!("(+{n} hp)"),
        PotionEffect::GreaterHeal(n) => format!("(+{n} hp)"),
        PotionEffect::FullHeal => "(full hp)".to_string(),
        PotionEffect::MaxHpUp(n) => format!("(+{n} max hp)"),
        PotionEffect::BuffAttack { amount, turns } => {
            format!("(+{amount} atk for {turns} turns)")
        }
        PotionEffect::BuffVision { amount, turns } => {
            format!("(+{amount} sight for {turns} turns)")
        }
        PotionEffect::CurePoison => "(cure poison)".to_string(),
    }
}

fn describe_scroll(s: ScrollKind) -> &'static str {
    match s {
        ScrollKind::Mapping => "(reveals level)",
        ScrollKind::Teleport => "(random teleport)",
        ScrollKind::Identify => "(identify)",
        ScrollKind::MagicMissile => "(zap nearest mob)",
        ScrollKind::ChainLightning => "(zap 3 nearby mobs)",
        ScrollKind::EnchantWeapon => "(+1 weapon)",
        ScrollKind::EnchantArmor => "(+1 armor)",
        ScrollKind::Fear => "(routs nearby)",
        ScrollKind::GreaterFear => "(routs nearby longer)",
        ScrollKind::Summon => "(summon allies)",
        ScrollKind::Legion => "(summon many allies)",
        ScrollKind::Light => "(extends FOV)",
        ScrollKind::Recall => "(to up-stair)",
    }
}

fn describe_ring(r: RingEffect) -> &'static str {
    match r {
        RingEffect::Regen => "regen +1/turn",
        RingEffect::Protection => "+1 def",
        RingEffect::Vision => "+2 sight",
    }
}

fn describe_amulet(a: AmuletEffect) -> &'static str {
    match a {
        AmuletEffect::TeleportControl => "controls teleports",
    }
}

fn describe_wand(k: WandKind) -> &'static str {
    match k {
        WandKind::Fire => "fire",
        WandKind::Cold => "cold",
        WandKind::Lightning => "lightning",
        WandKind::Storms => "storms",
    }
}

fn describe_throwable(t: ThrowableKind) -> &'static str {
    match t {
        ThrowableKind::OilFlask => "ignites tile",
        ThrowableKind::SmokeBomb => "clears aggro",
    }
}

fn take_chars(s: &str, n: usize) -> String {
    s.chars().take(n).collect()
}

