    }

    for attack in &attacks {
        let severity = if world.get::<&Player>(attack.target).is_ok() {
            Severity::Danger
        } else {
            Severity::Combat
        };
        log.push(
            format!(
                "{} hits {} for {}.",
                attack.attacker_name, attack.target_name, attack.damage
            ),
            severity,
        );
    }

    for attack in &attacks {
        apply_on_hit(world, log, attack.attacker, attack.target, &attack.target_name);
    }

    let mut killed: HashSet<Entity> = HashSet::new();
    for attack in attacks {
        let hp_after = world
            .get::<&Stats>(attack.target)
            .ok()
            .map(|stats| stats.hp)
            .unwrap_or(1);
        if hp_after <= 0 && killed.insert(attack.target) {
            on_kill(world, log, attack.attacker, attack.target, &attack.target_name);
        }
    }
}

fn roll_damage<R: Rng>(world: &World, attacker: Entity, target: Entity, rng: &mut R) -> i32 {
    let attack = world
        .get::<&Stats>(attacker)
        .ok()
        .map(|s| s.attack)
        .unwrap_or(0);
    let defense = world
        .get::<&Stats>(target)
        .ok()
        .map(|s| s.defense)
        .unwrap_or(0);
    let roll = if config::COMBAT.damage_roll_sides > 0 {
        rng.gen_range(1..=config::COMBAT.damage_roll_sides)
    } else {
        0
    };
    let raw = config::COMBAT.flat_damage_bonus + roll + attack;
    (raw - defense).max(config::COMBAT.minimum_damage)
}

fn apply_on_hit(
    world: &mut World,
    log: &mut MessageLog,
    attacker: Entity,
    target: Entity,
    target_name: &str,
) {
    let on_hit = match world.get::<&OnHit>(attacker) {
        Ok(o) => *o,
        Err(_) => return,
    };
    if on_hit.poison_turns > 0 {
        if let Ok(mut s) = world.get::<&mut StatusEffects>(target) {
            s.poison_turns = s.poison_turns.max(on_hit.poison_turns);
            s.poison_dmg = s.poison_dmg.max(on_hit.poison_dmg.max(1));
        }
        log.danger(format!("{target_name} is poisoned!"));
    }
    if on_hit.paralysis_turns > 0 {
        if let Ok(mut s) = world.get::<&mut StatusEffects>(target) {
            s.paralysis_turns = s.paralysis_turns.max(on_hit.paralysis_turns);
        }
        log.danger(format!("{target_name} is paralyzed!"));
    }
}

fn on_kill(
    world: &mut World,
    log: &mut MessageLog,
    attacker: Entity,
    target: Entity,
    target_name: &str,
) {
    let target_is_player = world.get::<&Player>(target).is_ok();
    if target_is_player {
        log.danger(format!("{target_name} died!"));
        // Tag the player with `Dead` so the main loop can switch to the
        // game-over screen; do NOT despawn (we still need stats for the
        // summary render).
        let _ = world.insert_one(target, Dead);
        return;
    }

    log.combat(format!("{target_name} dies!"));
    let xp = mob_xp(world, target).unwrap_or(0);
    let attacker_is_player = world.get::<&Player>(attacker).is_ok();
    if let Ok(mut prog) = world.get::<&mut Progression>(attacker) {
        prog.kills = prog.kills.saturating_add(1);
    }
    if attacker_is_player && xp > 0 {
        log.status(format!("you gain {xp} xp."));
        crate::run_state::award_xp(world, log, xp);
    }
    let _ = world.insert_one(target, Dead);
}

fn mob_xp(world: &World, entity: Entity) -> Option<i32> {
    if world.get::<&Mob>(entity).is_err() {
        return None;
    }
    let name = world.get::<&Name>(entity).ok()?;
    TEMPLATES
        .iter()
        .find(|t| t.name == name.0)
        .map(|t| t.xp)
}

fn name_of(world: &World, entity: Entity) -> String {
    world
        .get::<&Name>(entity)
        .map(|n| n.0.clone())
        .unwrap_or_else(|_| "something".to_string())
}

pub fn reap(world: &mut World) {
    let dead: Vec<Entity> = world
        .query::<&Dead>()
        .iter()
        .filter(|(e, _)| world.get::<&Player>(*e).is_err())
        .map(|(e, _)| e)
        .collect();
    for entity in dead {
        let _ = world.despawn(entity);
    }
}

fn attack_damages_target() {
        let mut world = World::new();
        let mut log = MessageLog::new();
        let attacker = world.spawn((
            Player,
            Stats::new(20, 5, 1, 1),
            Name("you".into()),
        ));
        let target = world.spawn((
            Mob,
            Stats::new(8, 2, 0, 1),
            Name("rat".into()),
        ));
        world.insert_one(attacker, WantsToAttack { target }).unwrap();
        let mut rng = Pcg64Mcg::seed_from_u64(0);
        resolve(&mut world, &mut log, &mut rng);
        let stats = *world.get::<&Stats>(target).unwrap();
        assert!(stats.hp < 8, "target should have taken damage");
        assert!(world.get::<&WantsToAttack>(attacker).is_err());
    }

fn lethal_attack_marks_dead_and_awards_xp() {
        let mut world = World::new();
        let mut log = MessageLog::new();
        let attacker = world.spawn((
            Player,
            Stats::new(20, 100, 0, 1),
            Progression::default(),
            Name("you".into()),
        ));
        let target = world.spawn((Mob, Stats::new(1, 0, 0, 1), Name("rat".into())));
        world.insert_one(attacker, WantsToAttack { target }).unwrap();
        let mut rng = Pcg64Mcg::seed_from_u64(7);
        resolve(&mut world, &mut log, &mut rng);
        assert!(world.get::<&Dead>(target).is_ok());
        let prog = *world.get::<&Progression>(attacker).unwrap();
        assert!(prog.xp >= 2, "rat awards >=2 xp; got {}", prog.xp);
        assert_eq!(prog.kills, 1);
        reap(&mut world);
        assert!(!world.contains(target));
    }

fn player_death_marks_game_over() {
        let mut world = World::new();
        let mut log = MessageLog::new();
        let attacker = world.spawn((
            Mob,
            Stats::new(8, 100, 0, 1),
            Name("orc".into()),
        ));
        let player = world.spawn((
            Player,
            Stats::new(1, 1, 0, 1),
            Progression::default(),
            Name("you".into()),
        ));
        world.insert_one(attacker, WantsToAttack { target: player }).unwrap();
        let mut rng = Pcg64Mcg::seed_from_u64(0);
        resolve(&mut world, &mut log, &mut rng);
        assert!(player_dead(&world));
        // Player not despawned even after reap.
        reap(&mut world);
        assert!(world.contains(player));
    }

fn damage_matches_attack_minus_defense_when_roll_is_disabled() {
        let mut world = World::new();
        let attacker = world.spawn((Player, Stats::new(10, 7, 0, 1), Name("you".into())));
        let target = world.spawn((Mob, Stats::new(10, 1, 3, 1), Name("jackal".into())));
        let mut rng = Pcg64Mcg::seed_from_u64(0);

        let damage = roll_damage(&world, attacker, target, &mut rng);

        assert_eq!(damage, 4);
    }

//! AI: turn an NPC's situation into either a `MoveIntent` or a
//! `WantsToAttack` intent.

use std::collections::HashSet;

use hecs::{Entity, World};
use rand::Rng;

use crate::config;
use crate::ecs::components::{
    Ai, AiKind, CasterHeal, Faction, Mob, MoveIntent, Player, Position, Renderable, Stats,
    StatusEffects, WantsToAttack,
};
use crate::map::Map;

pub fn plan<R: Rng>(
    world: &mut World,
    map: &Map,
    rng: &mut R,
    entity: Entity,
    moved_this_round: &HashSet<Entity>,
) {
    if status_skip(world, entity) {
        return;
    }
    handle_caster_heal(world, entity, rng);
    let view = match mob_view(world, entity) {
        Some(v) => v,
        None => return,
    };
    let can_attack = !moved_this_round.contains(&entity);
    let intent = match view.ai.kind {
        AiKind::Hostile => plan_hostile(world, map, rng, view, can_attack),
        AiKind::Sleeper { wake_radius } => {
            plan_sleeper(world, rng, entity, view, wake_radius, can_attack)
        }
        AiKind::Fleeing { flee_below_pct } => {
            plan_fleeing(world, map, rng, view, flee_below_pct, can_attack)
        }
        AiKind::Ranged { .. } => plan_ranged(world, map, rng, view, can_attack),
        AiKind::Mimic { revealed, .. } => {
            plan_mimic(world, map, rng, entity, view, revealed, can_attack)
        }
    };
    apply_intent(world, entity, intent);
}

#[derive(Clone, Copy, Debug)]
enum Intent {
    Move(i32, i32),
    Attack(Entity),
    None,
}

#[derive(Clone, Copy, Debug)]
struct MobView {
    x: i32,
    y: i32,
    ai: Ai,
    faction: Faction,
}

fn mob_view(world: &World, entity: Entity) -> Option<MobView> {
    let pos = world.get::<&Position>(entity).ok()?;
    let ai = world.get::<&Ai>(entity).ok()?;
    let faction = world
        .get::<&Faction>(entity)
        .map(|f| *f)
        .unwrap_or(Faction::Hostile);
    Some(MobView {
        x: pos.x,
        y: pos.y,
        ai: *ai,
        faction,
    })
}

fn status_skip(world: &World, entity: Entity) -> bool {
    world
        .get::<&StatusEffects>(entity)
        .map(|s| s.paralyzed())
        .unwrap_or(false)
}

fn handle_caster_heal<R: Rng>(world: &mut World, entity: Entity, rng: &mut R) {
    let caster = match world.get::<&CasterHeal>(entity) {
        Ok(c) => *c,
        Err(_) => return,
    };
    if rng.gen_range(0..100) >= caster.chance_pct {
        return;
    }
    if let Ok(mut stats) = world.get::<&mut Stats>(entity) {
        if stats.hp < stats.max_hp {
            stats.hp = (stats.hp + caster.heal_amount).min(stats.max_hp);
        }
    }
}

fn apply_intent(world: &mut World, entity: Entity, intent: Intent) {
    match intent {
        Intent::Move(dx, dy) => {
            let _ = world.insert_one(entity, MoveIntent::new(dx, dy));
        }
        Intent::Attack(target) => {
            let _ = world.insert_one(entity, WantsToAttack { target });
        }
        Intent::None => {}
    }
}

fn plan_hostile<R: Rng>(
    world: &World,
    map: &Map,
    rng: &mut R,
    view: MobView,
    can_attack: bool,
) -> Intent {
    let target_pos = match enemy_position_for(world, view) {
        Some(p) => p,
        None => return random_step(rng),
    };
    let dx = target_pos.0 - view.x;
    let dy = target_pos.1 - view.y;
    let dist_sq = dx * dx + dy * dy;
    let sight_sq = view.ai.sight_radius * view.ai.sight_radius;
    let afraid = world_status_afraid(world, view);
    if !can_attack && dx.abs() <= 1 && dy.abs() <= 1 {
        return Intent::None;
    }
    if dist_sq <= sight_sq && map.line_of_sight(view.x, view.y, target_pos.0, target_pos.1) {
        if afraid {
            return Intent::Move(-dx.signum(), -dy.signum());
        }
        return Intent::Move(dx.signum(), dy.signum());
    }
    random_step(rng)
}

fn plan_sleeper<R: Rng>(
    world: &mut World,
    rng: &mut R,
    entity: Entity,
    view: MobView,
    wake_radius: i32,
    can_attack: bool,
) -> Intent {
    let target = match enemy_position_for(world, view) {
        Some(p) => p,
        // No enemy at all → still drift around the room.
        None => return random_step(rng),
    };
    let dx = target.0 - view.x;
    let dy = target.1 - view.y;
    let dist_sq = dx * dx + dy * dy;
    if dist_sq <= wake_radius * wake_radius {
        if let Ok(mut ai) = world.get::<&mut Ai>(entity) {
            ai.kind = AiKind::Hostile;
        }
        if !can_attack && dx.abs() <= 1 && dy.abs() <= 1 {
            return Intent::None;
        }
        return Intent::Move(dx.signum(), dy.signum());
    }
    // Player is outside the wake radius — sleeper stays asleep, but its
    // body still shuffles around so the floor doesn't feel like a museum.
    random_step(rng)
}

fn plan_fleeing<R: Rng>(
    world: &World,
    map: &Map,
    rng: &mut R,
    view: MobView,
    flee_below_pct: i32,
    can_attack: bool,
) -> Intent {
    let target = match enemy_position_for(world, view) {
        Some(p) => p,
        None => return random_step(rng),
    };
    let dx = target.0 - view.x;
    let dy = target.1 - view.y;
    if mob_hp_pct(world, view) <= flee_below_pct {
        return Intent::Move(-dx.signum(), -dy.signum());
    }
    plan_hostile(world, map, rng, view, can_attack)
}

fn mob_hp_pct(world: &World, view: MobView) -> i32 {
    for (_, (pos, stats)) in world.query::<(&Position, &Stats)>().iter() {
        if pos.x == view.x && pos.y == view.y {
            return (stats.hp * 100) / stats.max_hp.max(1);
        }
    }
    100
}

fn plan_ranged<R: Rng>(
    world: &World,
    map: &Map,
    rng: &mut R,
    view: MobView,
    can_attack: bool,
) -> Intent {
    let (target_pos, target_entity) = match enemy_with_entity(world, view) {
        Some(p) => p,
        None => return random_step(rng),
    };
    let dx = target_pos.0 - view.x;
    let dy = target_pos.1 - view.y;
    let dist_sq = dx * dx + dy * dy;
    let sight_sq = view.ai.sight_radius * view.ai.sight_radius;
    if dist_sq > sight_sq
        || !map.line_of_sight(view.x, view.y, target_pos.0, target_pos.1)
    {
        // Out of sight: don't ranged-attack, just patrol the room.
        return random_step(rng);
    }
    if dist_sq <= config::WORLD.ranged_attack_range * config::WORLD.ranged_attack_range {
        if !can_attack {
            return Intent::None;
        }
        return Intent::Attack(target_entity);
    }
    Intent::Move(dx.signum(), dy.signum())
}

fn plan_mimic<R: Rng>(
    world: &mut World,
    map: &Map,
    rng: &mut R,
    entity: Entity,
    view: MobView,
    revealed: bool,
    can_attack: bool,
) -> Intent {
    let target = match enemy_position_for(world, view) {
        Some(p) => p,
        None => return Intent::None,
    };
    let dx = target.0 - view.x;
    let dy = target.1 - view.y;
    let adjacent = dx.abs() <= 1 && dy.abs() <= 1;
    if !revealed && !adjacent {
        return Intent::None;
    }
    if !revealed {
        // Reveal: switch glyph and AI.
        if let Ok(mut ai) = world.get::<&mut Ai>(entity) {
            ai.kind = AiKind::Hostile;
        }
        if let Ok(mut r) = world.get::<&mut Renderable>(entity) {
            r.glyph = 'm';
        }
    }
    let view = MobView {
        ai: Ai { kind: AiKind::Hostile, sight_radius: view.ai.sight_radius },
        ..view
    };
    plan_hostile(world, map, rng, view, can_attack)
}

/// Look up the position of the closest enemy entity to this mob, taking
/// faction into account: a `Hostile` mob targets `Player` and `PlayerAlly`
/// mobs; a `PlayerAlly` mob targets `Hostile` mobs.
fn enemy_position_for(world: &World, view: MobView) -> Option<(i32, i32)> {
    enemy_with_entity(world, view).map(|(p, _)| p)
}

fn enemy_with_entity(world: &World, view: MobView) -> Option<((i32, i32), Entity)> {
    match view.faction {
        Faction::Hostile => {
            // Prefer the player; if player not in range, target nearest ally.
            for (e, (_, pos)) in world.query::<(&Player, &Position)>().iter() {
                return Some(((pos.x, pos.y), e));
            }
            nearest_ally(world, view)
        }
        Faction::PlayerAlly => nearest_hostile(world, view),
    }
}

fn nearest_ally(world: &World, view: MobView) -> Option<((i32, i32), Entity)> {
    let mut best: Option<((i32, i32), Entity, i32)> = None;
    for (e, (_, pos, fac)) in world.query::<(&Mob, &Position, &Faction)>().iter() {
        if *fac != Faction::PlayerAlly {
            continue;
        }
        let d = (pos.x - view.x).pow(2) + (pos.y - view.y).pow(2);
        if best.map_or(true, |(_, _, bd)| d < bd) {
            best = Some(((pos.x, pos.y), e, d));
        }
    }
    best.map(|(p, e, _)| (p, e))
}

fn nearest_hostile(world: &World, view: MobView) -> Option<((i32, i32), Entity)> {
    let mut best: Option<((i32, i32), Entity, i32)> = None;
    for (e, (_, pos, fac)) in world.query::<(&Mob, &Position, &Faction)>().iter() {
        if *fac != Faction::Hostile {
            continue;
        }
        let d = (pos.x - view.x).pow(2) + (pos.y - view.y).pow(2);
        if best.map_or(true, |(_, _, bd)| d < bd) {
            best = Some(((pos.x, pos.y), e, d));
        }
    }
    best.map(|(p, e, _)| (p, e))
}

fn world_status_afraid(world: &World, view: MobView) -> bool {
    for (_, (_, pos, status)) in world.query::<(&Mob, &Position, &StatusEffects)>().iter() {
        if pos.x == view.x && pos.y == view.y {
            return status.afraid();
        }
    }
    false
}

fn random_step<R: Rng>(rng: &mut R) -> Intent {
    if rng.gen_bool(0.2) {
        return Intent::None;
    }
    let dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)];
    let (dx, dy) = dirs[rng.gen_range(0..dirs.len())];
    Intent::Move(dx, dy)
}

/// Bresenham line-of-sight check: walks the line from (x0, y0) to (x1, y1)
/// and returns false the moment it hits an opaque tile (excluding the
/// endpoints themselves).
#[cfg(test)]
mod tests {
    use super::*;
    use crate::ecs::components::{BlocksTile, Mob, Player};
    use crate::ecs::systems::movement;
    use crate::map::{Map, Tile};
    use rand::SeedableRng;
    use rand_pcg::Pcg64Mcg;

    fn open_room(w: i32, h: i32) -> Map {
        let mut m = Map::new(w, h);
        for y in 1..h - 1 {
            for x in 1..w - 1 {
                m.set(x, y, Tile::Floor);
            }
        }
        m
    }

    #[test]
    fn hostile_mob_steps_toward_visible_player() {
        let map = open_room(30, 10);
        let mut world = World::new();
        world.spawn((Position::new(5, 5), Player, BlocksTile));
        let mob = world.spawn((
            Position::new(15, 5),
            Mob,
            BlocksTile,
            Ai::hostile(20),
            Faction::Hostile,
        ));
        let mut rng = Pcg64Mcg::seed_from_u64(0);
        plan(&mut world, &map, &mut rng, mob, &HashSet::new());
        let _ = movement::apply(&mut world, &map);
        let pos = *world.get::<&Position>(mob).expect("mob pos");
        assert_eq!(pos, Position::new(14, 5));
    }

}

