        None => return random_step(rng),
    };
    let dx = target_pos.0 - view.x;
    let dy = target_pos.1 - view.y;
    let dist_sq = dx * dx + dy * dy;
    let sight_sq = view.ai.sight_radius * view.ai.sight_radius;
    let afraid = world_status_afraid(world, view);
    if !can_attack && dx.abs() <= 1 && dy.abs() <= 1 {
        return Intent::None;
    }
    if dist_sq <= sight_sq && map.line_of_sight(view.x, view.y, target_pos.0, target_pos.1) {
        if afraid {
            return Intent::Move(-dx.signum(), -dy.signum());
        }
        return Intent::Move(dx.signum(), dy.signum());
    }
    random_step(rng)
}

fn plan_sleeper<R: Rng>(
    world: &mut World,
    rng: &mut R,
    entity: Entity,
    view: MobView,
    wake_radius: i32,
    can_attack: bool,
) -> Intent {
    let target = match enemy_position_for(world, view) {
        Some(p) => p,
        // No enemy at all → still drift around the room.
        None => return random_step(rng),
    };
    let dx = target.0 - view.x;
    let dy = target.1 - view.y;
    let dist_sq = dx * dx + dy * dy;
    if dist_sq <= wake_radius * wake_radius {
        if let Ok(mut ai) = world.get::<&mut Ai>(entity) {
            ai.kind = AiKind::Hostile;
        }
        if !can_attack && dx.abs() <= 1 && dy.abs() <= 1 {
            return Intent::None;
        }
        return Intent::Move(dx.signum(), dy.signum());
    }
    // Player is outside the wake radius — sleeper stays asleep, but its
    // body still shuffles around so the floor doesn't feel like a museum.
    random_step(rng)
}

fn plan_fleeing<R: Rng>(
    world: &World,
    map: &Map,
    rng: &mut R,
    view: MobView,
    flee_below_pct: i32,
    can_attack: bool,
) -> Intent {
    let target = match enemy_position_for(world, view) {
        Some(p) => p,
        None => return random_step(rng),
    };
    let dx = target.0 - view.x;
    let dy = target.1 - view.y;
    if mob_hp_pct(world, view) <= flee_below_pct {
        return Intent::Move(-dx.signum(), -dy.signum());
    }
    plan_hostile(world, map, rng, view, can_attack)
}

fn mob_hp_pct(world: &World, view: MobView) -> i32 {
    for (_, (pos, stats)) in world.query::<(&Position, &Stats)>().iter() {
        if pos.x == view.x && pos.y == view.y {
            return (stats.hp * 100) / stats.max_hp.max(1);
        }
    }
    100
}

fn plan_ranged<R: Rng>(
    world: &World,
    map: &Map,
    rng: &mut R,
    view: MobView,
    can_attack: bool,
) -> Intent {
    let (target_pos, target_entity) = match enemy_with_entity(world, view) {
        Some(p) => p,
        None => return random_step(rng),
    };
    let dx = target_pos.0 - view.x;
    let dy = target_pos.1 - view.y;
    let dist_sq = dx * dx + dy * dy;
    let sight_sq = view.ai.sight_radius * view.ai.sight_radius;
    if dist_sq > sight_sq
        || !map.line_of_sight(view.x, view.y, target_pos.0, target_pos.1)
    {
        // Out of sight: don't ranged-attack, just patrol the room.
        return random_step(rng);
    }
    if dist_sq <= config::WORLD.ranged_attack_range * config::WORLD.ranged_attack_range {
        if !can_attack {
            return Intent::None;
        }
        return Intent::Attack(target_entity);
    }
    Intent::Move(dx.signum(), dy.signum())
}

fn plan_mimic<R: Rng>(
    world: &mut World,
    map: &Map,
    rng: &mut R,
    entity: Entity,
    view: MobView,
    revealed: bool,
    can_attack: bool,
) -> Intent {
    let target = match enemy_position_for(world, view) {
        Some(p) => p,
        None => return Intent::None,
    };
    let dx = target.0 - view.x;
    let dy = target.1 - view.y;
    let adjacent = dx.abs() <= 1 && dy.abs() <= 1;
    if !revealed && !adjacent {
        return Intent::None;
    }
    if !revealed {
        // Reveal: switch glyph and AI.
        if let Ok(mut ai) = world.get::<&mut Ai>(entity) {
            ai.kind = AiKind::Hostile;
        }
        if let Ok(mut r) = world.get::<&mut Renderable>(entity) {
            r.glyph = 'm';
        }
    }
    let view = MobView {
        ai: Ai { kind: AiKind::Hostile, sight_radius: view.ai.sight_radius },
        ..view
    };
    plan_hostile(world, map, rng, view, can_attack)
}

fn enemy_position_for(world: &World, view: MobView) -> Option<(i32, i32)> {
    enemy_with_entity(world, view).map(|(p, _)| p)
}

fn enemy_with_entity(world: &World, view: MobView) -> Option<((i32, i32), Entity)> {
    match view.faction {
        Faction::Hostile => {
            // Prefer the player; if player not in range, target nearest ally.
            for (e, (_, pos)) in world.query::<(&Player, &Position)>().iter() {
                return Some(((pos.x, pos.y), e));
            }
            nearest_ally(world, view)
        }
        Faction::PlayerAlly => nearest_hostile(world, view),
    }
}

fn nearest_ally(world: &World, view: MobView) -> Option<((i32, i32), Entity)> {
    let mut best: Option<((i32, i32), Entity, i32)> = None;
    for (e, (_, pos, fac)) in world.query::<(&Mob, &Position, &Faction)>().iter() {
        if *fac != Faction::PlayerAlly {
            continue;
        }
        let d = (pos.x - view.x).pow(2) + (pos.y - view.y).pow(2);
        if best.map_or(true, |(_, _, bd)| d < bd) {
            best = Some(((pos.x, pos.y), e, d));
        }
    }
    best.map(|(p, e, _)| (p, e))
}

fn nearest_hostile(world: &World, view: MobView) -> Option<((i32, i32), Entity)> {
    let mut best: Option<((i32, i32), Entity, i32)> = None;
    for (e, (_, pos, fac)) in world.query::<(&Mob, &Position, &Faction)>().iter() {
        if *fac != Faction::Hostile {
            continue;
        }
        let d = (pos.x - view.x).pow(2) + (pos.y - view.y).pow(2);
        if best.map_or(true, |(_, _, bd)| d < bd) {
            best = Some(((pos.x, pos.y), e, d));
        }
    }
    best.map(|(p, e, _)| (p, e))
}

fn world_status_afraid(world: &World, view: MobView) -> bool {
    for (_, (_, pos, status)) in world.query::<(&Mob, &Position, &StatusEffects)>().iter() {
        if pos.x == view.x && pos.y == view.y {
            return status.afraid();
        }
    }
    false
}

fn random_step<R: Rng>(rng: &mut R) -> Intent {
    if rng.gen_bool(0.2) {
        return Intent::None;
    }
    let dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)];
    let (dx, dy) = dirs[rng.gen_range(0..dirs.len())];
    Intent::Move(dx, dy)
}

fn open_room(w: i32, h: i32) -> Map {
        let mut m = Map::new(w, h);
        for y in 1..h - 1 {
            for x in 1..w - 1 {
                m.set(x, y, Tile::Floor);
            }
        }
        m
    }

fn hostile_mob_steps_toward_visible_player() {
        let map = open_room(30, 10);
        let mut world = World::new();
        world.spawn((Position::new(5, 5), Player, BlocksTile));
        let mob = world.spawn((
            Position::new(15, 5),
            Mob,
            BlocksTile,
            Ai::hostile(20),
            Faction::Hostile,
        ));
        let mut rng = Pcg64Mcg::seed_from_u64(0);
        plan(&mut world, &map, &mut rng, mob, &HashSet::new());
        let _ = movement::apply(&mut world, &map);
        let pos = *world.get::<&Position>(mob).expect("mob pos");
        assert_eq!(pos, Position::new(14, 5));
    }

//! Render systems: tiles first, entities on top. Both write into the
//! shared draw buffer; the buffer's diff flush decides what hits stdout.

use crossterm::style::Color;
use hecs::World;

use crate::ecs::components::{FieldOfView, Player, Position, Renderable, StatusEffects};
use crate::map::fov::Visibility;
use crate::map::Map;
use crate::ui::{Buffer, Cell};

/// Draw visible/revealed tiles offset by camera (cam_x, cam_y) so the map
/// can be larger than the terminal viewport.
pub fn draw_map(
    map: &Map,
    fov: Option<&Visibility>,
    buffer: &mut Buffer,
    y_offset: u16,
    cam_x: i32,
    cam_y: i32,
) {
    let bw = buffer.width() as i32;
    let bh = buffer.height() as i32;
    let oy = y_offset as i32;
    for (x, y, tile) in map.iter() {
        let sx = x - cam_x;
        let sy = y - cam_y + oy;
        if sx < 0 || sy < oy || sx >= bw || sy >= bh {
            continue;
        }
        let (visible, revealed) = match fov {
            Some(v) => (v.is_visible(x, y), v.is_revealed(x, y)),
            None => (true, true),
        };
        if !visible && !revealed {
            buffer.put(sx as u16, sy as u16, Cell::BLANK);
            continue;
        }
        let fg = if visible { tile.fg() } else { Color::DarkGrey };
        buffer.put(sx as u16, sy as u16, Cell::new(tile.glyph(), fg, tile.bg()));
    }
}

/// Locates the player's FOV component so `draw_map` and `draw_entities`
/// stay in sync with the same visibility data.
pub fn player_fov(world: &World) -> Option<Visibility> {
    let mut found: Option<Visibility> = None;
    for (_, (_, fov)) in world.query::<(&Player, &FieldOfView)>().iter() {
        found = Some(fov.view.clone());
        break;
    }
    found
}

pub fn draw_entities(
    world: &World,
    fov: Option<&Visibility>,
    buffer: &mut Buffer,
    y_offset: u16,
    cam_x: i32,
    cam_y: i32,
) {
    let player_pos = world
        .query::<(&Player, &Position)>()
        .iter()
        .map(|(_, (_, p))| (p.x, p.y))
        .next();
    let mut entries: Vec<(i32, i32, Renderable)> = world
        .query::<(&Position, &Renderable)>()
        .iter()
        .filter(|(entity, (pos, _))| {
            let in_fov = match fov {
                Some(v) => v.is_visible(pos.x, pos.y),
                None => true,
            };
            if !in_fov {
                return false;
            }
            // Invisible mobs only render when adjacent to the player.
            if let Ok(status) = world.get::<&StatusEffects>(*entity) {
                if status.invisible {
                    if let Some((px, py)) = player_pos {
                        return (pos.x - px).abs() <= 1 && (pos.y - py).abs() <= 1;
                    }
                    return false;
                }
            }
            true
        })
        .map(|(_, (pos, render))| (pos.x, pos.y, *render))
        .collect();
    entries.sort_by_key(|(_, _, r)| r.layer);

    let w = buffer.width() as i32;
    let h = buffer.height() as i32;
    let oy = y_offset as i32;
    for (x, y, render) in entries {
        let sx = x - cam_x;
        let sy = y - cam_y + oy;
        if sx < 0 || sy < oy || sx >= w || sy >= h {
            continue;
        }
        buffer.put(
            sx as u16,
            sy as u16,
            Cell::new(render.glyph, render.fg, render.bg),
        );
    }
}

pub fn draw_map(
    map: &Map,
    fov: Option<&Visibility>,
    buffer: &mut Buffer,
    y_offset: u16,
    cam_x: i32,
    cam_y: i32,
) {
    let bw = buffer.width() as i32;
    let bh = buffer.height() as i32;
    let oy = y_offset as i32;
    for (x, y, tile) in map.iter() {
        let sx = x - cam_x;
        let sy = y - cam_y + oy;
        if sx < 0 || sy < oy || sx >= bw || sy >= bh {
            continue;
        }
        let (visible, revealed) = match fov {
            Some(v) => (v.is_visible(x, y), v.is_revealed(x, y)),
            None => (true, true),
        };
        if !visible && !revealed {
            buffer.put(sx as u16, sy as u16, Cell::BLANK);
            continue;
        }
        let fg = if visible { tile.fg() } else { Color::DarkGrey };
        buffer.put(sx as u16, sy as u16, Cell::new(tile.glyph(), fg, tile.bg()));
    }
}

pub fn player_fov(world: &World) -> Option<Visibility> {
    let mut found: Option<Visibility> = None;
    for (_, (_, fov)) in world.query::<(&Player, &FieldOfView)>().iter() {
        found = Some(fov.view.clone());
        break;
