    if eq.armor == Some(item) {
        if let ItemKind::Armor { defense_bonus } = kind {
            if let Ok(mut s) = world.get::<&mut Stats>(player) {
                s.defense -= defense_bonus;
            }
        }
        if let Ok(mut e) = world.get::<&mut Equipment>(player) {
            e.armor = None;
        }
