pub fn mark_all_dirty(world: &mut World) {
    let entities: Vec<hecs::Entity> =
        world.query::<&FieldOfView>().iter().map(|(e, _)| e).collect();
    for entity in entities {
        if let Ok(mut fov) = world.get::<&mut FieldOfView>(entity) {
            fov.dirty = true;
        }
    }
