        let y = rng.gen_range(room.y..room.y + room.h);
        if !tile_has_blocker(world, x, y) {
            spawn_mob(world, template, x, y, depth);
            return;
        }
    }
}

fn spawn_mob(world: &mut World, t: &MobTemplate, x: i32, y: i32, depth: u32) {
