fn main() -> Result<()> {
    let opts = parse_args()?;
    if opts.dump {
        return dump_maps(opts.seed, opts.dump_count, opts.dump_width, opts.dump_height);
    }
    install_panic_hook();
    let guard = TermGuard::enter()?;
    let result = app::drive(opts);
    guard.leave()?;
    result
}

