//! Static game-data tables (mobs, items, prefabs). Kept separate from ECS
//! and systems so balance changes don't churn the engine code.

pub mod items;
pub mod mobs;

//! Static mob definitions. Templates carry both base stats and any optional
//! "extras" — `OnHit` riders, `Regen`, `CasterHeal`, `Summoner`, `Flying`,
//! and the `AiKind` so spawn code can attach the right components.

use crossterm::style::Color;

use crate::ecs::components::{AiKind, OnHit};

#[derive(Clone, Copy, Debug)]
pub struct MobTemplate {
    pub name: &'static str,
    pub glyph: char,
    pub fg: Color,
    pub max_hp: i32,
    pub attack: i32,
    pub defense: i32,
    pub move_tiles: i32,
    pub sight: i32,
    pub xp: i32,
    pub difficulty: u32,
    pub min_depth: u32,
    pub ai: AiKind,
    pub on_hit: Option<OnHit>,
    pub regen_per_turn: i32,
    pub invisible: bool,
    pub caster_heal: Option<(i32, i32)>, // (heal_amount, chance_pct)
    pub summoner_chance: Option<i32>,
    pub flying: bool,
}

const fn base(
    name: &'static str,
    glyph: char,
    fg: Color,
    max_hp: i32,
    attack: i32,
    defense: i32,
    move_tiles: i32,
    sight: i32,
    xp: i32,
    difficulty: u32,
    min_depth: u32,
) -> MobTemplate {
    MobTemplate {
        name,
        glyph,
        fg,
        max_hp,
        attack,
        defense,
        move_tiles,
        sight,
        xp,
        difficulty,
        min_depth,
        ai: AiKind::Hostile,
        on_hit: None,
        regen_per_turn: 0,
        invisible: false,
        caster_heal: None,
        summoner_chance: None,
        flying: false,
    }
